async (params, browser) => {
  // Open Discogs
  await browser.open(`https://www.discogs.com/artist/${params.artist_id}`)

  // Wait for page
  await browser.waitForSelector('h1, .profile, .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const name = document.querySelector('h1')?.textContent?.trim() || ''; const bio = document.querySelector('.profile, [class*="bio"]')?.textContent?.trim()?.slice(0, 500) || ''; const members = []; document.querySelectorAll('[class*="member"] a, .group_members a').forEach(m => members.push(m.textContent?.trim())); return { name, bio, members, url: window.location.href };`)

  return result
}
